import anthropic
import json
import math

client = anthropic.Anthropic()

# The semantic store from earlier (simplified for this example)
KNOWLEDGE_BASE = {
    "doc-1": {"title": "Refund Policy", "content": "Full refunds within 30 days. After 30 days, manager discretion."},
    "doc-2": {"title": "Shipping Policy", "content": "Standard: 5-7 days. Express: 2 days, $9.99 extra."},
    "doc-3": {"title": "Return Conditions", "content": "Items must be unused and in original packaging. Electronics have 15-day return window."},
}

def search_knowledge_base(query: str, top_k: int = 3) -> str:
    query_words = set(query.lower().split())
    results = []
    for doc_id, doc in KNOWLEDGE_BASE.items():
        doc_words = set(doc["content"].lower().split())
        overlap = len(query_words & doc_words) / max(len(query_words | doc_words), 1)
        if overlap > 0:
            results.append((overlap, doc_id, doc))
    results.sort(reverse=True)
    return json.dumps({
        "results": [
            {"doc_id": doc_id, "title": doc["title"], "excerpt": doc["content"][:200]}
            for _, doc_id, doc in results[:top_k]
        ],
        "total_found": len(results),
    })

AGENTIC_RAG_SYSTEM = """
You are a customer support agent. Use search_knowledge_base to look up answers.
You may search multiple times if one search doesn't fully answer the question.
When you have a complete answer, call task_complete.
If the knowledge base doesn't contain an answer, call task_failed.
"""

TOOLS = [
    {
        "name": "search_knowledge_base",
        "description": "Search the internal knowledge base for relevant documents.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Search terms to find relevant documents"},
                "top_k": {"type": "integer", "default": 3, "description": "Number of results to return"},
            },
            "required": ["query"],
        },
    },
    {"name": "task_complete",
     "description": "Submit a complete answer.",
     "input_schema": {"type": "object", "properties": {"answer": {"type": "string"}}, "required": ["answer"]}},
    {"name": "task_failed",
     "description": "Call when no answer is found.",
     "input_schema": {"type": "object", "properties": {"reason": {"type": "string"}}, "required": ["reason"]}},
]

DISPATCH = {"search_knowledge_base": search_knowledge_base}

def run_agentic_rag(user_question: str, max_iterations: int = 8) -> dict:
    messages = [{"role": "user", "content": user_question}]

    for iteration in range(1, max_iterations + 1):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=AGENTIC_RAG_SYSTEM,
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        for block in tool_calls:
            if block.name in ("task_complete", "task_failed"):
                return {"status": block.name, "result": block.input, "iterations": iteration}

        if not tool_calls:
            text = next((b.text for b in resp.content if b.type == "text"), "")
            return {"status": "stuck", "result": text, "iterations": iteration}

        results = []
        for block in tool_calls:
            fn = DISPATCH.get(block.name)
            result = fn(**block.input) if fn else json.dumps({"error": "Unknown"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})

    return {"status": "max_iterations", "iterations": max_iterations}

outcome = run_agentic_rag("Can I return a laptop I bought 3 weeks ago?")
print(outcome)
# Agent searches "return laptop" → finds return conditions doc
# Agent searches "refund 3 weeks" → finds refund policy doc (within 30 days)
# Synthesises: yes, within 30 days + original packaging required
